import { useState } from "react";
import { useNavigate } from "react-router-dom";
import "../styles/circles.css";
import "./LoginScreen.css";

const SIZE_OPTIONS = [
  { step: 1, label: "S", previewHeight: 28, previewFont: 11 },
  { step: 2, label: "M", previewHeight: 40, previewFont: 14 },
  { step: 3, label: "L", previewHeight: 56, previewFont: 18 },
];

export default function LoginScreen() {
  const navigate = useNavigate();
  const [sizeStep, setSizeStep] = useState(2);

  const btnSizeClass = `login-btn--size-${sizeStep}`;

  return (
    <div className="login-screen">

      {/* Background circles */}
      <div className="circle circle-a" />
      <div className="circle circle-b" />
      <div className="circle circle-c" />
      <div className="circle circle-d" />

      {/* Logo + tagline */}
      <div className="login-logo-wrap">
        <div className="login-logo">synova</div>
        <div className="login-tagline">Helping you with every word and step.</div>
      </div>

      {/* Buttons */}
      <div className="login-buttons">
        <button className={`login-btn login-btn--primary ${btnSizeClass}`} onClick={() => navigate("/signup")}>
          Sign Up
        </button>
        <button className={`login-btn login-btn--secondary ${btnSizeClass}`} onClick={() => navigate("/login-form")}>
          Log In
        </button>
      </div>

      {/* Size scale */}
      <div className="size-scale-wrap">
        <span className="size-scale-label">Button size</span>
        <div className="size-scale">
          {SIZE_OPTIONS.map(({ step, label, previewHeight, previewFont }) => (
            <button
              key={step}
              className={`size-tile ${sizeStep === step ? "size-tile--active" : ""}`}
              onClick={() => setSizeStep(step)}
            >
              <div
                className="size-tile-preview"
                style={{ height: previewHeight, fontSize: previewFont }}
              >
                {label}
              </div>
            </button>
          ))}
        </div>
      </div>

    </div>
  );
}
